"""Teilübersetzungen für Bottled Kraken."""

FR_HELP_PRIVACY_AND_LEGAL_TEXTS_TRANSLATIONS = {
    "help_html_ssh": "\n    <div class=\"card\">\n        <div class=\"h1\">Accès distant via tunnel SSH</div><br>\n        Un tunnel SSH est utile lorsque ton serveur LM tourne sur une autre machine,\n        mais y est uniquement lié à <code>127.0.0.1</code> et n’est donc pas directement accessible sur le réseau.\n    </div>\n\n    <div class=\"card\">\n        <div class=\"h2\">Que se passe-t-il alors ?</div><br>\n        Le tunnel redirige un port local de ton ordinateur vers un port de la machine distante.\n        Pour Bottled Kraken, cela donne alors l’impression que le serveur LM fonctionne localement sur ton propre ordinateur.\n    </div>\n\n            <div class=\"card\">\n                <div class=\"h2\">Exemple</div><br>\n                <b>Sur la machine A</b><br>\n                Démarrer LM Studio<br>\n                Trouver l’adresse IP de la machine A, par exemple avec :\n                <pre>ipconfig\nhostname -I</pre>\n                Supposons que l’adresse IP soit :\n                <pre>192.168.1.50</pre>\n                <b>Sur la machine B</b><br>\n                Ouvrir le tunnel SSH :\n                <pre>ssh -L 1234:127.0.0.1:1234 user@192.168.1.50</pre>\n                <b>À utiliser sur la machine B</b><br>\n                Test dans le terminal :\n                <pre>curl http://127.0.0.1:1234/v1/models</pre>\n                Saisir ceci dans Bottled Kraken :\n                <pre>http://127.0.0.1:1234/v1</pre>\n            </div>\n\n    <div class=\"card\">\n        <div class=\"h2\">Déroulement typique</div>\n        <ol>\n            <li>Démarrer LM Studio sur la machine A</li>\n            <li>Trouver l’adresse IP de la machine A</li>\n            <li>Ouvrir le tunnel SSH sur la machine B avec cette adresse IP</li>\n            <li>Tester sur la machine B si <code>http://127.0.0.1:1234/v1/models</code> est accessible</li>\n            <li>Saisir <code>http://127.0.0.1:1234/v1</code> dans Bottled Kraken</li>\n        </ol>\n    </div>\n\n    <div class=\"card warn\">\n        <div class=\"h2\">Important</div>\n        <ul>\n            <li>Dans Bottled Kraken, tu ne saisis <b>pas</b> la commande SSH.</li>\n            <li>Tu saisis toujours l’URL HTTP résultante, par exemple <code>http://127.0.0.1:1234/v1</code>.</li>\n            <li>Le tunnel SSH doit rester ouvert tant que Bottled Kraken doit utiliser le serveur.</li>\n        </ul>\n    </div>\n",
    "help_html_whisper_intro": "\n    <div class=\"card\">\n        <div class=\"h1\">Faster-Whisper</div>\n        <p>\n            Faster-Whisper est une reconnaissance vocale locale rapide.\n            Dans Bottled Kraken, tu peux l’utiliser pour réenregistrer des lignes OCR individuelles via le microphone\n            et les reprendre directement comme texte.\n        </p>\n    </div>\n\n    <div class=\"card\">\n        <div class=\"h2\">À quoi cela sert-il ?</div>\n        <ul>\n            <li>lorsqu’une ligne OCR est fortement endommagée ou a été mal reconnue</li>\n            <li>lorsque tu peux dicter certains champs ou noms plus rapidement que les taper</li>\n            <li>lorsque tu veux effectuer des corrections ciblées ligne par ligne</li>\n        </ul>\n    </div>\n\n    <div class=\"card\">\n        <div class=\"h2\">Qu’est-ce qui est téléchargé ?</div>\n        <p>\n            Le modèle <span class=\"badge\">Systran/faster-whisper-large-v3</span> est chargé.\n        </p>\n        <p class=\"muted\">\n            Avant le téléchargement, Bottled Kraken installe automatiquement les paquets Python nécessaires.\n            Le téléchargement proprement dit du modèle s’effectue via la CLI Hugging Face avec <code>hf download</code>.\n            Sous Linux et macOS, un environnement venv séparé est automatiquement utilisé pour cela.\n        </p>\n    </div>\n\n    <div class=\"card\">\n        <div class=\"h2\">Déroulement dans Bottled Kraken</div>\n        <ol>\n            <li>Télécharger le modèle Whisper ou rechercher un modèle existant</li>\n            <li>Sélectionner un microphone</li>\n            <li>Marquer une ligne</li>\n            <li>Démarrer l’enregistrement audio</li>\n            <li>La saisie vocale est transcrite localement et remplace la ligne</li>\n        </ol>\n    </div>\n",
    "help_html_shortcuts": "\n    <div class=\"card\">\n        <div class=\"h1\">Raccourcis clavier</div>\n        <table class=\"table\">\n            <tr><td class=\"section\" colspan=\"2\">Projet</td></tr>\n            <tr><td><span class=\"kbd\">Ctrl + S</span></td><td>Enregistrer le projet</td></tr>\n            <tr><td><span class=\"kbd\">Ctrl + Maj + S</span></td><td>Enregistrer le projet sous</td></tr>\n            <tr><td><span class=\"kbd\">Ctrl + I</span></td><td>Charger un projet</td></tr>\n            <tr><td><span class=\"kbd\">Ctrl + E</span></td><td>Exporter</td></tr>\n            <tr><td><span class=\"kbd\">Ctrl + Q</span></td><td>Quitter le programme</td></tr>\n\n            <tr><td class=\"section\" colspan=\"2\">OCR &amp; LM</td></tr>\n            <tr><td><span class=\"kbd\">Ctrl + K</span></td><td>Démarrer l’OCR Kraken</td></tr>\n            <tr><td><span class=\"kbd\">Ctrl + P</span></td><td>Arrêter l’OCR Kraken</td></tr>\n            <tr><td><span class=\"kbd\">Ctrl + L</span></td><td>Démarrer la révision LM</td></tr>\n            <tr><td><span class=\"kbd\">Ctrl + M</span></td><td>Démarrer Faster-Whisper / microphone</td></tr>\n\n            <tr><td class=\"section\" colspan=\"2\">Sélection</td></tr>\n            <tr><td><span class=\"kbd\">Ctrl + A</span></td><td>Tout sélectionner dans le contexte actuel</td></tr>\n            <tr><td><span class=\"kbd\">Suppr</span></td><td>Supprimer les lignes ou boîtes sélectionnées</td></tr>\n\n            <tr><td class=\"section\" colspan=\"2\">Touches de fonction</td></tr>\n            <tr><td><span class=\"kbd\">F1</span></td><td>Aide des raccourcis</td></tr>\n            <tr><td><span class=\"kbd\">F2</span></td><td>Charger le modèle de reconnaissance</td></tr>\n            <tr><td><span class=\"kbd\">F3</span></td><td>Charger le modèle de segmentation</td></tr>\n            <tr><td><span class=\"kbd\">F4</span></td><td>Saisir l’URL du serveur LM</td></tr>\n            <tr><td><span class=\"kbd\">F5</span></td><td>Lancer la détection LM</td></tr>\n            <tr><td><span class=\"kbd\">F6</span></td><td>Scanner les modèles Whisper + définir le premier microphone</td></tr>\n            <tr><td><span class=\"kbd\">F7</span></td><td>Afficher / masquer la fenêtre de log</td></tr>\n        </table>\n    </div>\n",
    "help_html_data_protection": "\n    <div class=\"card warn\">\n        <div class=\"h1\">Protection des données</div><br>\n        Les remarques suivantes résument le <b>mode de fonctionnement local standard</b>.\n        Elles ne remplacent pas une analyse au cas par cas.\n    </div>\n\n    <div class=\"card\">\n        <div class=\"h2\">Règle générale</div>\n        <ul>\n            <li>Les modèles locaux et les serveurs locaux sont en principe plus favorables à la protection des données, car les invites, documents et fichiers audio ne sont pas envoyés automatiquement à un service cloud.</li>\n            <li>Cela n’est vrai que tant que le logiciel est réellement utilisé <b>en local</b>, sans routage cloud ni exposition réseau.</li>\n            <li>Dès qu’il y a exposition sur le réseau, tunnel, reverse proxy, instance distante ou modèle cloud, la situation change.</li>\n        </ul>\n    </div>\n\n    <div class=\"card\">\n        <div class=\"h2\">LM Studio</div>\n        <ul>\n            <li>D’après la documentation officielle, LM Studio peut fonctionner entièrement hors ligne ; le chat local, le chat avec documents et le serveur local n’ont alors pas besoin d’internet.</li>\n            <li>La politique de confidentialité indique aussi explicitement que les messages, historiques de chat et documents ne sont pas transmis hors du système par défaut.</li>\n            <li>Cela vaut pour l’usage local. Si l’on active un accès réseau ou des fonctions distantes, il faut vérifier où partent les données.</li>\n        </ul>\n    </div>\n\n    <div class=\"card\">\n        <div class=\"h2\">Ollama</div>\n        <ul>\n            <li>Ollama fonctionne localement par défaut sur <code>http://localhost:11434</code> ; aucune authentification n’est requise pour l’usage purement local de l’API.</li>\n            <li>Un déploiement limité à <code>localhost</code> reste donc sur votre propre machine.</li>\n            <li>Important : Ollama prend aussi en charge des <b>modèles cloud</b>. Dès qu’ils sont utilisés, le flux de travail n’est plus purement local.</li>\n        </ul>\n    </div>\n\n    <div class=\"card\">\n        <div class=\"h2\">Jan</div>\n        <ul>\n            <li>Jan se présente comme privacy-first et stocke les données localement dans son propre dossier de données.</li>\n            <li>Son API locale est limitée par défaut à <code>127.0.0.1</code>, ce qui constitue la configuration la plus sûre pour un usage individuel.</li>\n            <li>Jan propose aussi des réglages d’analyse / suivi et des journaux serveur détaillés. Avant un usage en production, il est donc utile de vérifier consciemment ce qui est journalisé localement et si un accès réseau a été activé.</li>\n        </ul>\n    </div>\n\n    <div class=\"card\">\n        <div class=\"h2\">GPT4All</div>\n        <ul>\n            <li>GPT4All met en avant l’exécution locale sur votre propre matériel.</li>\n            <li>Son serveur API n’écoute par défaut que sur <code>localhost</code>, et non depuis d’autres appareils du réseau.</li>\n            <li>Avec <b>LocalDocs</b>, des documents locaux peuvent être intégrés au flux de travail ; même dans ce cas, l’emplacement de stockage et le contrôle d’accès à l’appareil restent importants.</li>\n        </ul>\n    </div>\n\n    <div class=\"card\">\n        <div class=\"h2\">text-generation-webui &amp; LocalAI</div>\n        <ul>\n            <li><b>text-generation-webui</b> décrit son API compatible OpenAI / Anthropic comme 100&nbsp;% hors ligne et privée, et précise aussi ne pas créer de logs.</li>\n            <li><b>LocalAI</b> se présente comme une pile locale compatible OpenAI et affirme garder les données privées et sécurisées.</li>\n            <li>Pour les deux projets, la règle pratique reste la même : dès que l’API est exposée sur le réseau, placée derrière un reverse proxy ou ouverte à plusieurs utilisateurs, il faut sécuriser soi-même les accès, les logs, les sauvegardes et les droits d’administration.</li>\n        </ul>\n    </div>\n\n    <div class=\"card\">\n        <div class=\"h2\">faster-whisper</div><br>\n        faster-whisper est une implémentation locale de Whisper basée sur CTranslate2.\n        Dans Bottled Kraken, un dossier de modèle local est chargé et un fichier WAV local est transcrit.\n        Tant que ce flux reste local, le traitement audio reste lui aussi local.\n    </div>\n\n    <div class=\"card warn\">\n        <div class=\"h2\">Limitations importantes</div>\n        <ul>\n            <li>Le téléchargement initial des modèles nécessite naturellement un accès à Internet.</li>\n            <li>Même un serveur «&nbsp;local&nbsp;» peut exposer des données personnelles si l’appareil lui-même n’est pas suffisamment sécurisé.</li>\n            <li>Pour les administrations, archives, entreprises ou organismes de recherche, les seules propriétés d’un outil ne suffisent pas ; il faut aussi prendre en compte l’emplacement de stockage, les rôles, les logs, les sauvegardes, les règles de suppression et les politiques internes.</li>\n            <li>Une licence logicielle ou une politique de confidentialité ne remplace pas une analyse RGPD, contractuelle ou opérationnelle adaptée au déploiement réel.</li>\n        </ul>\n    </div>\n\n    <div class=\"card\">\n        <div class=\"h2\">Sources officielles</div>\n        <ul>\n            <li><a href=\"https://lmstudio.ai/docs/app/offline\">LM Studio Docs – Offline Operation</a></li>\n            <li><a href=\"https://lmstudio.ai/privacy\">LM Studio Desktop App Privacy Policy</a></li>\n            <li><a href=\"https://docs.ollama.com/api/authentication\">Ollama Docs – Authentication</a></li>\n            <li><a href=\"https://docs.ollama.com/cloud\">Ollama Docs – Cloud</a></li>\n            <li><a href=\"https://ollama.com/privacy\">Ollama – Privacy Policy</a></li>\n            <li><a href=\"https://www.jan.ai/docs/desktop/privacy\">Jan Docs – Privacy</a></li>\n            <li><a href=\"https://www.jan.ai/docs/desktop/data-folder\">Jan Docs – Data Folder</a></li>\n            <li><a href=\"https://www.jan.ai/docs/desktop/api-server\">Jan Docs – Local API Server</a></li>\n            <li><a href=\"https://docs.gpt4all.io/gpt4all_api_server/home.html\">GPT4All Docs – API Server</a></li>\n            <li><a href=\"https://github.com/nomic-ai/gpt4all\">GPT4All – Dépôt</a></li>\n            <li><a href=\"https://github.com/oobabooga/text-generation-webui/wiki/12-%E2%80%90-OpenAI-API\">text-generation-webui – Wiki API OpenAI / Anthropic</a></li>\n            <li><a href=\"https://localai.io/docs/overview/\">LocalAI Docs – Overview</a></li>\n            <li><a href=\"https://github.com/SYSTRAN/faster-whisper\">SYSTRAN / faster-whisper</a></li>\n            <li><a href=\"https://github.com/opennmt/ctranslate2\">CTranslate2</a></li>\n        </ul>\n    </div>\n",
    "help_html_legal": "\n    <div class=\"card warn\">\n        <div class=\"h1\">Mentions légales</div><br>\n        Les remarques suivantes constituent une orientation générale et ne remplacent pas un conseil juridique.\n        Pour tout cas d’usage concret, la situation juridique doit être examinée individuellement.\n    </div>\n\n    <div class=\"card ok\">\n        <div class=\"h2\">Bottled Kraken</div>\n        <ul>\n            <li><b>Licence du dépôt :</b> MIT</li>\n            <li><b>En bref :</b> en cas de redistribution du logiciel, de publication de versions modifiées ou de distribution d’un paquet construit à partir de celui-ci, les conditions de la MIT doivent être respectées.</li>\n            <li><b>Important :</b> cela reste distinct des licences des bibliothèques intégrées et des modèles utilisés.</li>\n        </ul>\n    </div>\n\n    <div class=\"card\">\n        <div class=\"h2\">Kraken</div>\n        <ul>\n            <li>Kraken est la base OCR de Bottled Kraken.</li>\n            <li>Le projet est placé sous <b>Apache License 2.0</b>.</li>\n            <li>En cas de redistribution, le texte de licence, les mentions de copyright et d’éventuelles obligations NOTICE sont particulièrement importants.</li>\n        </ul>\n    </div>\n\n    <div class=\"card\">\n        <div class=\"h2\">faster-whisper</div>\n        <ul>\n            <li>faster-whisper est utilisé dans Bottled Kraken pour les fonctions locales de transcription vocale.</li>\n            <li>Le projet est sous <b>licence MIT</b>.</li>\n            <li>Des conditions séparées peuvent toutefois s’appliquer aux modèles et aux dépendances additionnelles.</li>\n        </ul>\n    </div>\n\n    <div class=\"card\">\n        <div class=\"h2\">LM Studio</div>\n        <ul>\n            <li>LM Studio est utilisé en option comme serveur de modèles local ou connecté.</li>\n            <li>Les documents de référence sont ici surtout les <b>Terms of Service</b> et la <b>Privacy Policy</b> officielles.</li>\n            <li>En plus de cela, chaque modèle chargé via LM Studio peut avoir sa propre licence.</li>\n        </ul>\n    </div>\n\n    <div class=\"card\">\n        <div class=\"h2\">Ollama</div>\n        <ul>\n            <li>Le logiciel du dépôt officiel est placé sous <b>licence MIT</b>.</li>\n            <li>Cela reste en général simple pour un usage local ; en cas de redistribution d’un logiciel modifié, les mentions de licence et de copyright demeurent importantes.</li>\n            <li>Il faut distinguer cela des <b>fonctions cloud</b>, des règles de confidentialité et surtout des licences propres aux modèles exécutés.</li>\n        </ul>\n    </div>\n\n    <div class=\"card\">\n        <div class=\"h2\">Jan</div>\n        <ul>\n            <li>Le dépôt Jan est publié comme projet open source ; sa licence de dépôt est <b>AGPL-3.0</b>.</li>\n            <li>L’AGPL est particulièrement importante lorsque des versions modifiées sont mises à disposition via un réseau.</li>\n            <li>Comme pour les autres outils, des conditions supplémentaires peuvent s’appliquer aux modèles intégrés et aux fournisseurs cloud externes.</li>\n        </ul>\n    </div>\n\n    <div class=\"card\">\n        <div class=\"h2\">GPT4All</div>\n        <ul>\n            <li>Le dépôt officiel GPT4All est sous <b>licence MIT</b>.</li>\n            <li>La licence logicielle est permissive ; il faut néanmoins vérifier séparément les licences des modèles, l’usage de la marque et les composants tiers.</li>\n        </ul>\n    </div>\n\n    <div class=\"card\">\n        <div class=\"h2\">text-generation-webui (oobabooga)</div>\n        <ul>\n            <li>Le projet est sous <b>AGPL-3.0</b>.</li>\n            <li>Ce cadre est juridiquement plus strict que MIT ou Apache, en particulier lorsqu’on modifie le logiciel ou qu’on le met à disposition via un réseau.</li>\n        </ul>\n    </div>\n\n    <div class=\"card\">\n        <div class=\"h2\">LocalAI</div>\n        <ul>\n            <li>D’après le dépôt officiel, LocalAI est sous <b>licence MIT</b>.</li>\n            <li>Comme pour les autres serveurs, les licences des modèles, les composants supplémentaires et les règles d’usage organisationnelles doivent être examinés séparément.</li>\n        </ul>\n    </div>\n\n    <div class=\"card\">\n        <div class=\"h2\">PySide6 / Qt for Python</div>\n        <ul>\n            <li>L’interface graphique de Bottled Kraken repose sur PySide6 / Qt for Python.</li>\n            <li>Qt for Python utilise des régimes de licence pouvant impliquer la <b>LGPL</b> ou une licence commerciale Qt, selon le composant et le mode de distribution.</li>\n            <li>Pour la redistribution, le packaging et les produits combinés propriétaires, la situation de licence Qt doit être vérifiée séparément.</li>\n        </ul>\n    </div>\n\n    <div class=\"card warn\">\n        <div class=\"h2\">Remarque supplémentaire sur les modèles et les contenus</div>\n        <ul>\n            <li>La licence logicielle d’une application doit toujours être distinguée de la licence des modèles OCR, vocaux ou IA qui y sont chargés.</li>\n            <li>Le traitement de documents protégés par le droit d’auteur, de données personnelles ou de fonds d’archives sensibles nécessite aussi une évaluation juridique distincte.</li>\n            <li>Cette fenêtre ne fournit qu’un aperçu compact, et non une analyse juridique contraignante pour un cas particulier.</li>\n        </ul>\n    </div>\n\n    <div class=\"card\">\n        <div class=\"h2\">Sources officielles</div>\n        <ul>\n            <li><a href=\"https://github.com/Testatost/Bottled-Kraken\">Bottled Kraken – Dépôt</a></li>\n            <li><a href=\"https://github.com/mittagessen/kraken\">Kraken – Dépôt</a></li>\n            <li><a href=\"https://kraken.re/7.0/index.html\">Kraken – Documentation</a></li>\n            <li><a href=\"https://github.com/SYSTRAN/faster-whisper\">faster-whisper – Dépôt</a></li>\n            <li><a href=\"https://lmstudio.ai/app-terms\">LM Studio – Terms of Service</a></li>\n            <li><a href=\"https://lmstudio.ai/privacy\">LM Studio – Privacy Policy</a></li>\n            <li><a href=\"https://github.com/ollama/ollama\">Ollama – Dépôt</a></li>\n            <li><a href=\"https://github.com/ollama/ollama/blob/main/LICENSE\">Ollama – Licence MIT</a></li>\n            <li><a href=\"https://github.com/janhq/jan\">Jan – Dépôt</a></li>\n            <li><a href=\"https://docs.gpt4all.io/gpt4all_api_server/home.html\">GPT4All – Documentation du serveur API</a></li>\n            <li><a href=\"https://github.com/nomic-ai/gpt4all/blob/main/LICENSE.txt\">GPT4All – Licence MIT</a></li>\n            <li><a href=\"https://github.com/oobabooga/text-generation-webui\">text-generation-webui – Dépôt</a></li>\n            <li><a href=\"https://github.com/oobabooga/text-generation-webui/blob/main/LICENSE\">text-generation-webui – AGPL-3.0</a></li>\n            <li><a href=\"https://localai.io/docs/overview/\">LocalAI – Overview</a></li>\n            <li><a href=\"https://github.com/mudler/LocalAI/blob/master/LICENSE\">LocalAI – Licence MIT</a></li>\n            <li><a href=\"https://doc.qt.io/qtforpython-6/\">Qt for Python – Documentation</a></li>\n            <li><a href=\"https://doc.qt.io/qtforpython-6/licenses.html\">Qt for Python – Licences</a></li>\n        </ul>\n    </div>\n"
}
